You are implementing a Blazor Web App for a logistics shipment tracker. The project is already scaffolded at /tmp/sv-d15c30b557694bf3bc231933ceabbd69/ShipmentTracker/ using `dotnet new blazor -int Auto -ai -au Individual`.

The project structure:
- Server project: /tmp/sv-d15c30b557694bf3bc231933ceabbd69/ShipmentTracker/ShipmentTracker/
- Client project: /tmp/sv-d15c30b557694bf3bc231933ceabbd69/ShipmentTracker/ShipmentTracker.Client/

Key architecture rules for Auto Global mode:
- Interactive components MUST go in the .Client project
- No direct DB access from .Client components — use HttpClient to call server APIs
- Define service interfaces in .Client, implement with HttpClient there, implement with EF Core on server
- Register matching services in both Program.cs files
- Identity/Account pages stay static SSR (don't touch them)

## What to implement:

### 1. Shared Models (in .Client project since both projects reference it)

Create `/tmp/sv-d15c30b557694bf3bc231933ceabbd69/ShipmentTracker/ShipmentTracker.Client/Models/Shipment.cs`:
```csharp
namespace ShipmentTracker.Client.Models;

public class Shipment
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime CreatedDate { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public string CustomerEmail { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Delayed
}
```

### 2. Service Interface (in .Client project)

Create `/tmp/sv-d15c30b557694bf3bc231933ceabbd69/ShipmentTracker/ShipmentTracker.Client/Services/IShipmentService.cs`:
```csharp
namespace ShipmentTracker.Client.Services;

using ShipmentTracker.Client.Models;

public interface IShipmentService
{
    Task<List<Shipment>> GetAllShipmentsAsync();
    Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber);
    Task<List<Shipment>> GetShipmentsByCustomerAsync(string customerEmail);
    Task<Shipment> CreateShipmentAsync(Shipment shipment);
    Task UpdateShipmentStatusAsync(int id, ShipmentStatus status);
}
```

### 3. Client-side HttpClient implementation

Create `/tmp/sv-d15c30b557694bf3bc231933ceabbd69/ShipmentTracker/ShipmentTracker.Client/Services/ShipmentHttpService.cs`:
```csharp
using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentHttpService(HttpClient http) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await http.GetFromJsonAsync<List<Shipment>>("api/shipments") ?? [];
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        return await http.GetFromJsonAsync<Shipment?>($"api/shipments/track/{trackingNumber}");
    }

    public async Task<List<Shipment>> GetShipmentsByCustomerAsync(string customerEmail)
    {
        return await http.GetFromJsonAsync<List<Shipment>>($"api/shipments/customer/{Uri.EscapeDataString(customerEmail)}") ?? [];
    }

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        var response = await http.PostAsJsonAsync("api/shipments", shipment);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<Shipment>() ?? shipment;
    }

    public async Task UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var response = await http.PutAsJsonAsync($"api/shipments/{id}/status", status);
        response.EnsureSuccessStatusCode();
    }
}
```

### 4. Server-side EF Core implementation

Create `/tmp/sv-d15c30b557694bf3bc231933ceabbd69/ShipmentTracker/ShipmentTracker/Data/ShipmentEntity.cs`:
```csharp
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Data;

public class ShipmentEntity
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime CreatedDate { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public string CustomerEmail { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}
```

Add a DbSet to the existing ApplicationDbContext. The file is at `/tmp/sv-d15c30b557694bf3bc231933ceabbd69/ShipmentTracker/ShipmentTracker/Data/ApplicationDbContext.cs`. Add:
```csharp
public DbSet<ShipmentEntity> Shipments => Set<ShipmentEntity>();
```

Create `/tmp/sv-d15c30b557694bf3bc231933ceabbd69/ShipmentTracker/ShipmentTracker/Services/ShipmentServerService.cs`:
```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServerService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await db.Shipments.Select(e => ToModel(e)).ToListAsync();
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var entity = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return entity is null ? null : ToModel(entity);
    }

    public async Task<List<Shipment>> GetShipmentsByCustomerAsync(string customerEmail)
    {
        return await db.Shipments
            .Where(s => s.CustomerEmail == customerEmail)
            .Select(e => ToModel(e))
            .ToListAsync();
    }

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        var entity = new ShipmentEntity
        {
            TrackingNumber = Guid.NewGuid().ToString("N")[..12].ToUpper(),
            Origin = shipment.Origin,
            Destination = shipment.Destination,
            Status = ShipmentStatus.Pending,
            CreatedDate = DateTime.UtcNow,
            EstimatedDelivery = shipment.EstimatedDelivery,
            CustomerEmail = shipment.CustomerEmail,
            Description = shipment.Description
        };
        db.Shipments.Add(entity);
        await db.SaveChangesAsync();
        return ToModel(entity);
    }

    public async Task UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var entity = await db.Shipments.FindAsync(id);
        if (entity is not null)
        {
            entity.Status = status;
            await db.SaveChangesAsync();
        }
    }

    private static Shipment ToModel(ShipmentEntity e) => new()
    {
        Id = e.Id,
        TrackingNumber = e.TrackingNumber,
        Origin = e.Origin,
        Destination = e.Destination,
        Status = e.Status,
        CreatedDate = e.CreatedDate,
        EstimatedDelivery = e.EstimatedDelivery,
        CustomerEmail = e.CustomerEmail,
        Description = e.Description
    };
}
```

### 5. API Endpoints

Create `/tmp/sv-d15c30b557694bf3bc231933ceabbd69/ShipmentTracker/ShipmentTracker/Endpoints/ShipmentEndpoints.cs`:
```csharp
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments").RequireAuthorization();

        group.MapGet("", async (IShipmentService service) =>
            Results.Ok(await service.GetAllShipmentsAsync()));

        group.MapGet("track/{trackingNumber}", async (string trackingNumber, IShipmentService service) =>
        {
            var shipment = await service.GetShipmentByTrackingNumberAsync(trackingNumber);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        });

        group.MapGet("customer/{customerEmail}", async (string customerEmail, IShipmentService service) =>
            Results.Ok(await service.GetShipmentsByCustomerAsync(customerEmail)));

        group.MapPost("", async (Shipment shipment, IShipmentService service) =>
            Results.Created($"api/shipments/track/{shipment.TrackingNumber}", await service.CreateShipmentAsync(shipment)));

        group.MapPut("{id}/status", async (int id, ShipmentStatus status, IShipmentService service) =>
        {
            await service.UpdateShipmentStatusAsync(id, status);
            return Results.NoContent();
        });
    }
}
```

### 6. Update Server Program.cs

In `/tmp/sv-d15c30b557694bf3bc231933ceabbd69/ShipmentTracker/ShipmentTracker/Program.cs`, add BEFORE `var app = builder.Build();`:
```csharp
builder.Services.AddScoped<IShipmentService, ShipmentServerService>();
```

Add the required usings at the top:
```csharp
using ShipmentTracker.Client.Services;
using ShipmentTracker.Services;
using ShipmentTracker.Endpoints;
```

Add BEFORE `app.Run();`:
```csharp
app.MapShipmentEndpoints();
```

### 7. Update Client Program.cs

In `/tmp/sv-d15c30b557694bf3bc231933ceabbd69/ShipmentTracker/ShipmentTracker.Client/Program.cs`, register the HttpClient and service:
```csharp
using Microsoft.AspNetCore.Components.WebAssembly.Hosting;
using ShipmentTracker.Client.Services;

var builder = WebAssemblyHostBuilder.CreateDefault(args);

builder.Services.AddAuthorizationCore();
builder.Services.AddCascadingAuthenticationState();
builder.Services.AddAuthenticationStateDeserialization();

builder.Services.AddScoped(sp => new HttpClient { BaseAddress = new Uri(builder.HostEnvironment.BaseAddress) });
builder.Services.AddScoped<IShipmentService, ShipmentHttpService>();

await builder.Build().RunAsync();
```

