using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentHttpService(HttpClient http) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await http.GetFromJsonAsync<List<Shipment>>("api/shipments") ?? [];
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        return await http.GetFromJsonAsync<Shipment?>($"api/shipments/track/{trackingNumber}");
    }

    public async Task<List<Shipment>> GetShipmentsByCustomerAsync(string customerEmail)
    {
        return await http.GetFromJsonAsync<List<Shipment>>($"api/shipments/customer/{Uri.EscapeDataString(customerEmail)}") ?? [];
    }

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        var response = await http.PostAsJsonAsync("api/shipments", shipment);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<Shipment>() ?? shipment;
    }

    public async Task UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var response = await http.PutAsJsonAsync($"api/shipments/{id}/status", status);
        response.EnsureSuccessStatusCode();
    }
}
