@page "/shipments"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Shipments</PageTitle>

<h1>Shipments</h1>

<div class="mb-3">
    <button class="btn btn-success" @onclick="ShowCreateForm">+ New Shipment</button>
</div>

@if (showCreateForm)
{
    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title">Create New Shipment</h5>
            <div class="row g-3">
                <div class="col-md-6">
                    <label class="form-label">Origin</label>
                    <input class="form-control" @bind="newShipment.Origin" placeholder="City, Country" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Destination</label>
                    <input class="form-control" @bind="newShipment.Destination" placeholder="City, Country" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Customer Email</label>
                    <input class="form-control" type="email" @bind="newShipment.CustomerEmail" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Estimated Delivery</label>
                    <input class="form-control" type="date" @bind="newShipment.EstimatedDelivery" />
                </div>
                <div class="col-12">
                    <label class="form-label">Description</label>
                    <input class="form-control" @bind="newShipment.Description" placeholder="Package contents" />
                </div>
                <div class="col-12">
                    <button class="btn btn-primary me-2" @onclick="CreateShipment">Create</button>
                    <button class="btn btn-secondary" @onclick="CancelCreate">Cancel</button>
                </div>
            </div>
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (shipments.Count == 0)
{
    <p>No shipments found.</p>
}
else
{
    <div class="mb-3">
        <input class="form-control" placeholder="Filter by destination..." @bind="filterText" @bind:event="oninput" />
    </div>

    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Customer</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in FilteredShipments)
                {
                    <tr>
                        <td><code>@shipment.TrackingNumber</code></td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></td>
                        <td>@shipment.CustomerEmail</td>
                        <td>@shipment.EstimatedDelivery?.ToString("yyyy-MM-dd")</td>
                        <td>
                            <select class="form-select form-select-sm" value="@shipment.Status"
                                @onchange="e => UpdateStatus(shipment, e)">
                                @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                {
                                    <option value="@status">@status</option>
                                }
                            </select>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<Shipment>? shipments;
    private string filterText = string.Empty;
    private bool showCreateForm;
    private Shipment newShipment = new();

    private IEnumerable<Shipment> FilteredShipments =>
        shipments?.Where(s => string.IsNullOrEmpty(filterText) ||
            s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase)) ?? [];

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private void ShowCreateForm() => showCreateForm = true;
    private void CancelCreate()
    {
        showCreateForm = false;
        newShipment = new();
    }

    private async Task CreateShipment()
    {
        if (!string.IsNullOrWhiteSpace(newShipment.Origin) && !string.IsNullOrWhiteSpace(newShipment.Destination))
        {
            var created = await ShipmentService.CreateShipmentAsync(newShipment);
            shipments?.Insert(0, created);
            showCreateForm = false;
            newShipment = new();
        }
    }

    private async Task UpdateStatus(Shipment shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            shipment.Status = newStatus;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input class="form-control" placeholder="Enter tracking number..."
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="SearchShipment">Track</button>
        </div>
    </div>
</div>

@if (isLoading)
{
    <p><em>Searching...</em></p>
}
else if (searched && shipment is null)
{
    <div class="alert alert-warning">
        No shipment found with tracking number <strong>@searchedNumber</strong>.
    </div>
}
else if (shipment is not null)
{
    <div class="card">
        <div class="card-header">
            <h5 class="mb-0">Shipment <code>@shipment.TrackingNumber</code></h5>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Status</dt>
                        <dd><span class="badge @GetStatusBadgeClass(shipment.Status) fs-6">@shipment.Status</span></dd>
                        <dt>Origin</dt>
                        <dd>@shipment.Origin</dd>
                        <dt>Destination</dt>
                        <dd>@shipment.Destination</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Description</dt>
                        <dd>@(string.IsNullOrEmpty(shipment.Description) ? "—" : shipment.Description)</dd>
                        <dt>Created</dt>
                        <dd>@shipment.CreatedDate.ToString("yyyy-MM-dd")</dd>
                        <dt>Estimated Delivery</dt>
                        <dd class="fs-5 fw-bold text-primary">
                            @(shipment.EstimatedDelivery?.ToString("yyyy-MM-dd") ?? "Not yet determined")
                        </dd>
                    </dl>
                </div>
            </div>

            <!-- Progress indicator -->
            <div class="mt-3">
                <h6>Shipment Progress</h6>
                <div class="progress" style="height: 30px;">
                    <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                         role="progressbar"
                         style="width: @GetProgressPercent(shipment.Status)%">
                        @shipment.Status
                    </div>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private string searchedNumber = string.Empty;
    private Shipment? shipment;
    private bool isLoading;
    private bool searched;

    private async Task SearchShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isLoading = true;
        searched = false;
        shipment = null;

        try
        {
            searchedNumber = trackingNumber.Trim();
            shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(searchedNumber);
            searched = true;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await SearchShipment();
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Delivered => "bg-success",
        _ => "bg-primary"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 55,
        _ => 0
    };
}

@page "/my-shipments"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Components.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService
@inject AuthenticationStateProvider AuthStateProvider

<PageTitle>My Shipments</PageTitle>

<h1>My Shipments</h1>

@if (shipments is null)
{
    <p><em>Loading your shipments...</em></p>
}
else if (shipments.Count == 0)
{
    <div class="alert alert-info">You have no shipments associated with your account.</div>
}
else
{
    <div class="row">
        @foreach (var shipment in shipments)
        {
            <div class="col-md-6 mb-3">
                <div class="card">
                    <div class="card-body">
                        <h6 class="card-title">
                            <code>@shipment.TrackingNumber</code>
                            <span class="badge @GetStatusBadgeClass(shipment.Status) ms-2">@shipment.Status</span>
                        </h6>
                        <p class="card-text mb-1"><strong>From:</strong> @shipment.Origin → <strong>To:</strong> @shipment.Destination</p>
                        <p class="card-text mb-1"><strong>Description:</strong> @(string.IsNullOrEmpty(shipment.Description) ? "—" : shipment.Description)</p>
                        <p class="card-text">
                            <strong>Estimated Delivery:</strong>
                            <span class="text-primary fw-bold">
                                @(shipment.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "TBD")
                            </span>
                        </p>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private List<Shipment>? shipments;

    protected override async Task OnInitializedAsync()
    {
        var authState = await AuthStateProvider.GetAuthenticationStateAsync();
        var email = authState.User.Identity?.Name ?? string.Empty;
        if (!string.IsNullOrEmpty(email))
        {
            shipments = await ShipmentService.GetShipmentsByCustomerAsync(email);
        }
        else
        {
            shipments = [];
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

