using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServerService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await db.Shipments.Select(e => ToModel(e)).ToListAsync();
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var entity = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return entity is null ? null : ToModel(entity);
    }

    public async Task<List<Shipment>> GetShipmentsByCustomerAsync(string customerEmail)
    {
        return await db.Shipments
            .Where(s => s.CustomerEmail == customerEmail)
            .Select(e => ToModel(e))
            .ToListAsync();
    }

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        var entity = new ShipmentEntity
        {
            TrackingNumber = Guid.NewGuid().ToString("N")[..12].ToUpper(),
            Origin = shipment.Origin,
            Destination = shipment.Destination,
            Status = ShipmentStatus.Pending,
            CreatedDate = DateTime.UtcNow,
            EstimatedDelivery = shipment.EstimatedDelivery,
            CustomerEmail = shipment.CustomerEmail,
            Description = shipment.Description
        };
        db.Shipments.Add(entity);
        await db.SaveChangesAsync();
        return ToModel(entity);
    }

    public async Task UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var entity = await db.Shipments.FindAsync(id);
        if (entity is not null)
        {
            entity.Status = status;
            await db.SaveChangesAsync();
        }
    }

    private static Shipment ToModel(ShipmentEntity e) => new()
    {
        Id = e.Id,
        TrackingNumber = e.TrackingNumber,
        Origin = e.Origin,
        Destination = e.Destination,
        Status = e.Status,
        CreatedDate = e.CreatedDate,
        EstimatedDelivery = e.EstimatedDelivery,
        CustomerEmail = e.CustomerEmail,
        Description = e.Description
    };
}
```

